var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"마스터!","JPN":"マスター！","ENG":"Master!","TWN":"主人！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"어째서 배신자가 활개치는 이런 누추한 곳에......! 어서 몸을 피하셔야 해요!","JPN":"なぜ裏切り者が横行するこんなむさくるしい場所に……！　早く安全な場所に避難してください！","ENG":"The traitor does not deserve to be graced with your presence! Please, you must get to safety!","TWN":"這裡叛徒橫行，您怎麼可以來到如此髒亂的地方……！請您回避！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"바람도 잔잔한데 그만 바스락거리렴. 정신 사납구나.","JPN":"こんなにも風が穏やかなのに、あなたはどうしてそんななびくのかしら。気が散ってしょうがないわね。","ENG":"Quit your noisy rustling. You're disturbing the peaceful air.","TWN":"清風徐徐，就不要在那裡沙沙作響了，太吵了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"네......?","JPN":"え……？","ENG":"Master?","TWN":"什麼……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"자, 베로니카. 어서 저 잡초를 솎아내렴.","JPN":"さあ、ベロニカ。早くあの雑草を間引きなさい。","ENG":"Now, Veronica. Go on and pluck that weed.","TWN":"貝洛妮卡，快除掉那個雜草吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"기회는 아직 유효하단다.","JPN":"まだチャンスは有効よ。","ENG":"The offer I gave you still stands.","TWN":"你現在還有機會。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"기, 기다려 주세요!","JPN":"お、お待ちください！","ENG":"P-please wait!","TWN":"等、等等！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"분명, 배신자를 솎아내는 데에는 실패했지만 마스터에 대한 충성심은 변하지 않았습니다!","JPN":"確かに、裏切り者の間引きには失敗しましたが、マスターへの忠誠心に代わりはございません！","ENG":"Although I've clearly failed to pluck out the traitor, my loyalty for you has not changed!","TWN":"雖然我沒能除掉叛徒，但我對主人您的忠心卻從來沒有變過！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그런데...... 그런데 어째서 저를 잡초 취급 하시는 건가요!","JPN":"それなのに……どうして私を雑草と呼ぶのでしょうか？","ENG":"But why... Why are you treating me like a weed?","TWN":"可是……可是您為什麼只當我是雜草呢！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"정말 눈치가 없구나, 너는.","JPN":"本当にあなたって子は空気が読めないのね。","ENG":"You really are clueless, aren't you?","TWN":"你真是沒眼力。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그야 네가 마음에 안 들어서 그렇지.","JPN":"あなたが気に入らないからに決まってるじゃない。","ENG":"That's because I simply don't like you, of course.","TWN":"當然是因為我不喜歡你啊。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"마음에...... 안 들어서?","JPN":"気に……入らない？","ENG":"Because you don't... like me?","TWN":"不……喜歡？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래. 너처럼 비실거리고 분위기도 어두침침한 아이를 어디에 데려다 쓰겠니.","JPN":"そうよ。あなたのように弱くて暗い子に使い道があると思ってるの？","ENG":"That's right. What use would I have for a frail, gloomy urchin like you?","TWN":"像你這麼弱不禁風又陰森森的人能幹什麼。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"적당히 써먹다 폐기할 생각이었는데, 베로니카가 널 꽤 아끼는 것 같아서 내버려 둔 거란다.","JPN":"適当に使って廃棄するつもりだったのに、ベロニカはあなたのことが相当気に入ったようだからしばらく放っておいただけよ。","ENG":"I was planning to discard of you once you'd served me however little you could, but then I decided to let you be, since Veronica seemed to be quite fond of you.","TWN":"本想隨便用用就扔了的，沒想到貝洛妮卡還挺喜歡你，所以我才留你活命。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"베로니카도 참 상냥하지. 금방 질릴 줄 알았는데 아직도 미련을 못 버린 모양이야.","JPN":"ベロニカったらなんて優しいのかしら。そのうち飽きると思ったのに、まだ未練があるとはね。","ENG":"Oh, sweet Veronica. I thought you would get tired of her quickly, but you still seem to be somewhat attached.","TWN":"貝洛妮卡也是善良，本以為沒多久就會厭倦，沒想到現在也沒放棄。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"마, 마스터...... 제가 잘못 들은 거죠? 그렇죠?","JPN":"マ、マスター……今のは私の聞き間違えですよね？　そうですよね？","ENG":"M-Master... I must have misheard you, right?","TWN":"主、主人……是我聽錯了吧？對不對？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"네가 잘못 들었는지 아닌지는 내 알 바 아니잖니.","JPN":"あなたが聞き間違えたかどうかなんて知ったことではないわ。","ENG":"I really couldn't care less if you heard me correctly or not.","TWN":"你聽沒聽錯跟我沒什麼關係。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그러니 적어도 마지막만큼은 눈에 거슬리지 않게 얌전히 있으렴.","JPN":"せめて最後くらいは目障りにならないように大人しく黙ってなさい。","ENG":"So just shush and do not disturb me. That's the least you can do in your final moments.","TWN":"死到臨頭了，就不要這麼礙眼了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"나는 내가 기른 꽃과 얘기하고 싶으니까.","JPN":"私は育てた花と話がしたいの。","ENG":"I wish to speak to the flower that I've nurtured.","TWN":"我現在只想和我養的花好好說話。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"마, 마스터......","JPN":"マ、マスター……","ENG":"M-Master...","TWN":"主、主人……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"제가 당신의 결정에 의문을 품었을 때 내린 지시도...... 기회를 준 건가요?","JPN":"私があなたの決断に疑問を抱いた時にくださった指示も……チャンスを与えたということでしょうか？","ENG":"That order you gave me when I questioned your decision... Were you offering me a chance back then as well?","TWN":"我對您的決定有所懷疑的時候，您下達的指示……也是為了給我機會？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래. 한동안 쉬기 전에 저 아이를 없애 버리라고 했지.","JPN":"そうよ。しばらく休みに入る前にあの子を始末しろと言ったわけ。","ENG":"Yes. I told you to get rid of that child before you went on your hiatus.","TWN":"是的，我讓你在休息之前除掉那個孩子。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"솎아내야 할 잡초를 가지고 떠드는 건 순전히 저 아이 탓이라고 생각했거든.","JPN":"間引かれるべき雑草ごときに対して口を出すのは、あの子のせいだと思ったの。","ENG":"I figured she was the reason why you got so chatty over the weed to be plucked.","TWN":"你對需要除掉的雜草猶豫不決，我以為是那個孩子的問題。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 그 지시는 이미 거절했을 텐데요.","JPN":"しかしその指示はすでにお断りしているはずです。","ENG":"But I already declined that order.","TWN":"不過我記得我已經拒絕過您。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이제 와서 제게 다시 기회를 주는 건 어째서죠?","JPN":"なぜ今更私にチャンスを与えるのでしょうか。","ENG":"Why are you offering me another chance now?","TWN":"那為什麼現在又要給我機會？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"넌 내가 기른 최고의 꽃이야, 베로니카.","JPN":"あなたは私が育てた花の中でも最高の花よ、ベロニカ。","ENG":"You're the finest flower I've ever raised, Veronica.","TWN":"你是我養的最優秀的花朵，貝洛妮卡。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"오는 길에 시험 삼아 살짝 장난을 쳤는데, 아니나 다를까 멋지게 빠져나오더구나.","JPN":"ここに来る途中ちょっとしたイタズラを仕掛けたのに、案の定見事に抜け出したわね。","ENG":"I played a little trick on you on the way here just for kicks, and you magnificently slipped out of it, as I expected.","TWN":"今天你來的路上，我開了個小玩笑，果不其然，你很帥氣地擺脫了我設下的局。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그런 널 쉽게 놓아 줄리 없잖니. 네 몸도, 영혼도 모두 내 것이니까.","JPN":"そんなあなたを簡単に手放すはずがないでしょ。あなたの体も、魂も、全部私のものなんだから。","ENG":"There's no way I'd let such a beautiful creature slip through my fingers. You are mine, body and soul.","TWN":"我怎麼可能輕易放過你，你的身體和你的靈魂都是我的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"너라면 저 아이를 왜 놔뒀는지 이해할 줄 알았는데...... 내 기대가 너무 컸나?","JPN":"あなたならあの子をなぜ生かしておいたのか理解してくれると思ったのに……私が期待しすぎたのかしら？","ENG":"I thought you would understand why I left that child be... Perhaps my expectations were unwarranted?","TWN":"我以為你能理解我為什麼放過她……是我對你的期望太高了嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그럼...... 그렇다는 건...... 마스터는 처음부터 절 버리실 생각으로......","JPN":"それは……つまり……マスターは最初から私を捨てるつもりで……","ENG":"You mean... You were always planning to abandon me...","TWN":"那……主人您的意思是……您一開始就想拋棄我……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"죄송합니다, 마스터. 당신의 지시는 따를 수 없습니다.","JPN":"申し訳ございません、マスター。あなたの指示には従えません。","ENG":"I'm sorry, Master. I cannot follow your orders.","TWN":"對不起，主人。我無法遵從您的命令。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"예전에 전, 당신만이 제 영원한 주인님이라고 생각했었죠.","JPN":"以前の私はあなただけが自分の永遠のご主人様だと思っていました。","ENG":"There was a time when I thought you would be my sole Master forever.","TWN":"以前我認為，只有您才是我永遠的主人。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 그건 제 착각이었어요.","JPN":"しかしそれは私の勘違いでした。","ENG":"But I couldn't have been more mistaken.","TWN":"但那只是我的錯覺而已。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"자신에게 충성을 바친 아이들을 아무렇지 않게 꺾어 버리는 당신은......","JPN":"自分に忠誠を誓った子を平然と折ってしまうあなたには……","ENG":"With the way you heartlessly pluck out those children who have been nothing but loyal to you...","TWN":"無情地拋棄這些對你忠心耿耿的孩子們……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인이 될 자격이 없습니다.","JPN":"主になる資格がありません。","ENG":"You are not worthy of being anyone's master.","TWN":"你根本就沒有資格當主人。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래? 설마 이번에도 날 배신할 생각이니?","JPN":"そう？　まさか、今回も私を裏切るつもり？","ENG":"Is that so? Are you about to betray me yet again?","TWN":"是嗎？所以這次你又想背叛我？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"새 주인 노릇을 해 주던 사람이 꽤 마음에 들었나 보구나?","JPN":"新しくできた主がかなり気に入ってしまったようね。","ENG":"It sounds like you've taken quite a liking to this new master of yours, hmm?","TWN":"看來你是很喜歡你的新主人？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네. 정확합니다.","JPN":"はい、そのとおりです。","ENG":"Yes. Precisely.","TWN":"是的，你說的對。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"절 친구라고 말해 주셨고, 꼭 다시 돌아올 거라고 믿어 주셨던 그 분이야말로......","JPN":"私を友達と言ってくださり、いつか帰ってくると信じてくれたあの方こそ……","ENG":"He called me friend, and trusted that I would return...","TWN":"他當我是朋友，堅信我會回來，所以他才是……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"제 영원한 주인님이십니다.","JPN":"私の永遠のご主人様です。","ENG":"He is my true master.","TWN":"我永遠的主人。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};